<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Kanban Board</title>
  <style>
    * { box-sizing: border-box; margin: 0; padding: 0; }
    body {
      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, sans-serif;
      background: #f4f5f7;
      min-height: 100vh;
      padding: 24px;
    }
    .board {
      display: flex;
      gap: 16px;
      max-width: 1200px;
      margin: 0 auto;
      height: calc(100vh - 48px);
      min-height: 600px;
    }
    .column {
      flex: 1;
      background: #ebecf0;
      border-radius: 12px;
      display: flex;
      flex-direction: column;
      min-width: 0;
    }
    .column-header {
      display: flex;
      align-items: center;
      justify-content: space-between;
      padding: 16px;
      font-weight: 600;
      font-size: 14px;
      text-transform: uppercase;
      letter-spacing: 0.5px;
      color: #172b4d;
    }
    .column-header .count {
      background: #0052cc;
      color: white;
      font-size: 12px;
      font-weight: 600;
      padding: 2px 8px;
      border-radius: 12px;
      min-width: 24px;
      text-align: center;
    }
    .card-container {
      flex: 1;
      overflow-y: auto;
      padding: 0 12px 12px;
      display: flex;
      flex-direction: column;
      gap: 8px;
      min-height: 100px;
    }
    .card-container.drag-over {
      background: rgba(0, 82, 204, 0.1);
      border-radius: 8px;
    }
    .card {
      background: white;
      border-radius: 8px;
      padding: 12px;
      box-shadow: 0 1px 2px rgba(9, 30, 66, 0.15);
      cursor: grab;
      transition: box-shadow 0.15s ease, transform 0.15s ease;
      user-select: none;
    }
    .card:hover {
      box-shadow: 0 4px 8px rgba(9, 30, 66, 0.15);
      transform: translateY(-1px);
    }
    .card.dragging {
      opacity: 0.5;
      cursor: grabbing;
      box-shadow: 0 8px 16px rgba(9, 30, 66, 0.2);
    }
    .card-content {
      display: flex;
      align-items: flex-start;
      justify-content: space-between;
      gap: 8px;
    }
    .card-title {
      font-size: 14px;
      line-height: 1.4;
      color: #172b4d;
      word-wrap: break-word;
      flex: 1;
    }
    .card-del {
      background: none;
      border: none;
      color: #6b778c;
      cursor: pointer;
      padding: 4px;
      border-radius: 4px;
      display: flex;
      align-items: center;
      justify-content: center;
      flex-shrink: 0;
      transition: background 0.15s ease, color 0.15s ease;
    }
    .card-del:hover {
      background: #ffebe9;
      color: #de350b;
    }
    .card-del:focus-visible {
      outline: 2px solid #0052cc;
      outline-offset: 2px;
    }
    .add-card-form {
      display: flex;
      gap: 8px;
      padding: 16px;
      max-width: 400px;
      margin: 0 auto 24px;
    }
    #new-card {
      flex: 1;
      padding: 10px 12px;
      border: 2px solid #dfe1e6;
      border-radius: 6px;
      font-size: 14px;
      font-family: inherit;
      transition: border-color 0.15s ease, box-shadow 0.15s ease;
    }
    #new-card:focus {
      outline: none;
      border-color: #0052cc;
      box-shadow: 0 0 0 3px rgba(0, 82, 204, 0.15);
    }
    #add-card {
      background: #0052cc;
      color: white;
      border: none;
      border-radius: 6px;
      padding: 10px 16px;
      font-size: 14px;
      font-weight: 500;
      font-family: inherit;
      cursor: pointer;
      transition: background 0.15s ease;
    }
    #add-card:hover {
      background: #0065ff;
    }
    #add-card:focus-visible {
      outline: 2px solid #0052cc;
      outline-offset: 2px;
    }
    @media (max-width: 768px) {
      .board {
        flex-direction: column;
        height: auto;
        min-height: auto;
      }
      .column {
        min-height: 300px;
      }
    }
  </style>
</head>
<body>
  <form class="add-card-form" id="add-form">
    <input type="text" id="new-card" placeholder="Enter card title..." aria-label="New card title">
    <button type="submit" id="add-card">Add Card</button>
  </form>

  <div class="board" id="board">
    <section class="column" id="col-todo" data-column="todo">
      <header class="column-header">
        <span>To Do</span>
        <span class="count">0</span>
      </header>
      <div class="card-container" data-column="todo"></div>
    </section>
    <section class="column" id="col-doing" data-column="doing">
      <header class="column-header">
        <span>Doing</span>
        <span class="count">0</span>
      </header>
      <div class="card-container" data-column="doing"></div>
    </section>
    <section class="column" id="col-done" data-column="done">
      <header class="column-header">
        <span>Done</span>
        <span class="count">0</span>
      </header>
      <div class="card-container" data-column="done"></div>
    </section>
  </div>

  <script>
    (function() {
      const STORAGE_KEY = 'kanban-board-state';
      const columns = ['todo', 'doing', 'done'];
      let cards = [];
      let draggedCardId = null;

      function generateId() {
        return Date.now().toString(36) + Math.random().toString(36).substr(2);
      }

      function saveState() {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(cards));
      }

      function loadState() {
        try {
          const stored = localStorage.getItem(STORAGE_KEY);
          if (stored) {
            cards = JSON.parse(stored);
          }
        } catch (e) {
          cards = [];
        }
      }

      function updateCounts() {
        columns.forEach(col => {
          const count = cards.filter(c => c.column === col).length;
          const countEl = document.querySelector(`[data-column="${col}"] .count`);
          if (countEl) countEl.textContent = count;
        });
      }

      function createCardElement(card) {
        const cardEl = document.createElement('div');
        cardEl.className = 'card';
        cardEl.draggable = true;
        cardEl.dataset.id = card.id;
        cardEl.innerHTML = `
          <div class="card-content">
            <span class="card-title">${escapeHtml(card.title)}</span>
            <button type="button" class="card-del" aria-label="Delete card">
              <svg width="16" height="16" viewBox="0 0 16 16" fill="currentColor">
                <path d="M5.5 5.5A.5.5 0 0 1 6 6v6a.5.5 0 0 1-1 0V6a.5.5 0 0 1 .5-.5zm2.5 0a.5.5 0 0 1 .5.5v6a.5.5 0 0 1-1 0V6a.5.5 0 0 1 .5-.5zm3 .5a.5.5 0 0 0-1 0v6a.5.5 0 0 0 1 0V6z"/>
                <path fill-rule="evenodd" d="M14.5 3a1 1 0 0 1-1 1H13v9a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V4h-.5a1 1 0 0 1-1-1V2a1 1 0 0 1 1-1H6a1 1 0 0 1 1-1h2a1 1 0 0 1 1 1h3.5a1 1 0 0 1 1 1v1zM4.118 4 4 4.059V13a1 1 0 0 0 1 1h6a1 1 0 0 0 1-1V4.059L11.882 4H4.118zM2.5 3V2h11v1h-11z"/>
              </svg>
            </button>
          </div>
        `;

        cardEl.addEventListener('dragstart', handleDragStart);
        cardEl.addEventListener('dragend', handleDragEnd);

        const delBtn = cardEl.querySelector('.card-del');
        delBtn.addEventListener('click', () => deleteCard(card.id));

        return cardEl;
      }

      function escapeHtml(text) {
        const div = document.createElement('div');
        div.textContent = text;
        return div.innerHTML;
      }

      function render() {
        columns.forEach(col => {
          const container = document.querySelector(`[data-column="${col}"] .card-container`);
          container.innerHTML = '';
          cards
            .filter(c => c.column === col)
            .forEach(card => {
              container.appendChild(createCardElement(card));
            });
        });
        updateCounts();
      }

      function addCard(title) {
        const trimmed = title.trim();
        if (!trimmed) return;
        const card = {
          id: generateId(),
          title: trimmed,
          column: 'todo'
        };
        cards.push(card);
        saveState();
        render();
      }

      function deleteCard(id) {
        cards = cards.filter(c => c.id !== id);
        saveState();
        render();
      }

      function moveCard(id, targetColumn) {
        const card = cards.find(c => c.id === id);
        if (card && card.column !== targetColumn) {
          card.column = targetColumn;
          saveState();
          render();
        }
      }

      function handleDragStart(e) {
        draggedCardId = this.dataset.id;
        this.classList.add('dragging');
        e.dataTransfer.effectAllowed = 'move';
        e.dataTransfer.setData('text/plain', draggedCardId);
      }

      function handleDragEnd() {
        this.classList.remove('dragging');
        document.querySelectorAll('.card-container.drag-over').forEach(el => {
          el.classList.remove('drag-over');
        });
        draggedCardId = null;
      }

      function handleDragOver(e) {
        e.preventDefault();
        e.dataTransfer.dropEffect = 'move';
        const container = this.closest('.card-container');
        if (container) container.classList.add('drag-over');
      }

      function handleDragLeave(e) {
        const container = this.closest('.card-container');
        if (container && !container.contains(e.relatedTarget)) {
          container.classList.remove('drag-over');
        }
      }

      function handleDrop(e) {
        e.preventDefault();
        const container = this.closest('.card-container');
        if (container) {
          container.classList.remove('drag-over');
          const targetColumn = container.dataset.column;
          if (draggedCardId && targetColumn) {
            moveCard(draggedCardId, targetColumn);
          }
        }
      }

      function init() {
        loadState();
        render();

        const form = document.getElementById('add-form');
        const input = document.getElementById('new-card');

        form.addEventListener('submit', e => {
          e.preventDefault();
          addCard(input.value);
          input.value = '';
          input.focus();
        });

        document.querySelectorAll('.card-container').forEach(container => {
          container.addEventListener('dragover', handleDragOver);
          container.addEventListener('dragleave', handleDragLeave);
          container.addEventListener('drop', handleDrop);
        });
      }

      if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', init);
      } else {
        init();
      }
    })();
  </script>
</body>
</html>
